// Build the Claude API request from webhook input
const body = $('Chat Webhook').first().json.body;

const storyContent = body.story_content || '';
const userMessage = body.user_message || '';
const chatHistory = body.chat_history || [];
const storyId = body.story_id || '';

// Build chat history for Claude messages format
const messages = [];

// Add previous chat history
for (const msg of chatHistory.slice(-10)) {
  messages.push({
    role: msg.role === 'user' ? 'user' : 'assistant',
    content: msg.content
  });
}

// Add the current user message with story context
messages.push({
  role: 'user',
  content: `CURRENT STORY CONTENT:\n${storyContent}\n\n---\n\nUSER MESSAGE:\n${userMessage}`
});

return [{
  json: {
    story_id: storyId,
    messages: messages
  }
}];

// Parse Claude response and return to frontend
const item = $input.first();
const storyId = $('Prepare Prompt').first().json.story_id;

let responseText = '';

try {
  if (item.json.content && Array.isArray(item.json.content)) {
    responseText = item.json.content.map(c => c.text || '').join('');
  } else if (typeof item.json === 'string') {
    responseText = item.json;
  } else if (item.json.error) {
    responseText = 'I encountered an error processing your request. Please try again.';
  }
} catch(e) {
  responseText = 'Something went wrong. Your conversation is saved — try again.';
}

return [{
  json: {
    response: responseText || 'No response generated',
    story_id: storyId
  }
}];
